		// Token: 0x060001A4 RID: 420 RVA: 0x0001CF74 File Offset: 0x0001B174
		protected void loadAllWare(string accountName)
		{
			try
			{
				DBLite.dbMu.Read("select Items,money from warehouse where AccountID = '" + accountName + "'");
				DBLite.dbMu.Fetch();
				this.ware[0].Num = 0;
				this.ware[0].items = DBLite.dbMu.GetAsBinary("Items");
				this.ware[0].Money = DBLite.dbMu.GetAsInteger("money");
				DBLite.dbMu.Close();
				this.comboVault.Items.Add("0");
				DBLite.dbMu.Read("SELECT items,SCFExtWare,money FROM ExtendedWarehouse WHERE AccountID = '" + accountName + "'");
				while (DBLite.dbMu.Fetch())
				{
					int num = this.ware.Length;
					Array.Resize<Warehouse.warehouses>(ref this.ware, num + 1);
					this.ware[num].items = DBLite.dbMu.GetAsBinary("Items");
					this.ware[num].Num = DBLite.dbMu.GetAsInteger("SCFExtWare");
					this.ware[num].Money = DBLite.dbMu.GetAsInteger("money");
					this.comboVault.Items.Add(this.ware[num].Num.ToString());
				}
				DBLite.dbMu.Close();
			}
			catch (Exception ex)
			{
				MessageBox.Show(ex.Message);
			}
		}

